// Typical Console debugging session:
// 1. Click the component element in Elements panel → $0 is set
const comp = ng.getComponent($0);
console.log(comp.items);           // inspect component state
comp.title = 'Debug Title';        // mutate a property
ng.applyChanges($0);               // trigger change detection to see it in the DOM

// Access a service from anywhere:
const injector = ng.getInjector(document.querySelector('app-root'));
const userService = injector.get(UserService);
console.log(userService.currentUser());

// Only break when the items array has more than 10 elements:
this.items.length > 10

// Only break for a specific user:
this.user?.id === 'user-42'

// Fix: add OnPush to components identified as slow in the profiler
import { ChangeDetectionStrategy } from '@angular/core';

@Component({
  selector: 'app-product-list',
  templateUrl: './product-list.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush  // add this
})
export class ProductListComponent { }

// Pattern: takeUntilDestroyed (Angular 16+)
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { DestroyRef, inject } from '@angular/core';

export class ProductListComponent {
  private destroyRef = inject(DestroyRef);

  ngOnInit() {
    this.productService.getAll()
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe(products => {
        this.products = products;
      });
    // No manual unsubscribe needed — cleaned up when component destroys
  }
}
